import{_ as s,C as r,o as t,c as n,a2 as a,E as l}from"./chunks/framework.BKG_UbFK.js";const f=JSON.parse('{"title":"Panel de Control","description":"","frontmatter":{},"headers":[],"relativePath":"es/features/dashboard.md","filePath":"es/features/dashboard.md"}'),i={name:"es/features/dashboard.md"};function d(c,e,u,p,h,m){const o=r("Screenshot");return t(),n("div",null,[e[0]||(e[0]=a('<h1 id="panel-de-control" tabindex="-1">Panel de Control <a class="header-anchor" href="#panel-de-control" aria-label="Permalink to &quot;Panel de Control&quot;">​</a></h1><p>El Panel de Control es la página de inicio del panel de Clearance. Ofrece un resumen de un vistazo del estado de autorización de tu aplicación - sin necesidad de configuración.</p><h2 id="que-muestra" tabindex="-1">Qué muestra <a class="header-anchor" href="#que-muestra" aria-label="Permalink to &quot;Qué muestra&quot;">​</a></h2><ul><li><strong>Total de roles</strong> - recuento de todos los roles de Spatie.</li><li><strong>Total de guards</strong> - recuento de todos los guards gestionados por Clearance (consulta <a href="/clearance-docs/es/features/guards.html">Guards</a>).</li><li><strong>Total de permisos</strong> - recuento de todos los permisos de Spatie.</li><li><strong>Grupos de permisos</strong> - el número de grupos de permisos distintos, derivado del prefijo de nomenclatura (el <code>group</code> en <code>group-action</code>, p. ej. <code>orders</code> en <code>orders-create</code>). Consulta <a href="/clearance-docs/es/features/permissions.html">Permisos</a> para la convención de nomenclatura.</li><li><strong>Asignaciones de rol contextuales</strong> - el número de asignaciones de rol limitadas a una instancia de modelo específica (una Tienda, un Tenant, un Proyecto). Consulta <a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a>.</li><li><strong>Top 5 roles por número de usuarios</strong> - los cinco roles con más usuarios asignados, ordenados.</li></ul>',4)),l(o,{src:"/screenshots/dashboard-page.png",alt:"Panel de Control de Clearance mostrando el recuento de roles, guards y permisos",caption:"El Panel de Control resume roles, guards, permisos, grupos, asignaciones contextuales y los roles principales."}),e[1]||(e[1]=a('<h2 id="acceder-al-panel-de-control" tabindex="-1">Acceder al Panel de Control <a class="header-anchor" href="#acceder-al-panel-de-control" aria-label="Permalink to &quot;Acceder al Panel de Control&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nombre de ruta</th><th>Descripción</th></tr></thead><tbody><tr><td><code>/clearance</code></td><td><code>clearance.home</code></td><td>Panel de Control</td></tr></tbody></table><p>Leer el Panel de Control requiere el permiso <code>clearance-access</code>, igual que cualquier otra sección del panel. Consulta <a href="/clearance-docs/es/features/super-admin.html#panel-access-fine-grained-write-permissions">Super Admin</a> para la tabla completa de control de acceso.</p><h2 id="incorporar-el-componente" tabindex="-1">Incorporar el componente <a class="header-anchor" href="#incorporar-el-componente" aria-label="Permalink to &quot;Incorporar el componente&quot;">​</a></h2><p>El Panel de Control es un componente Livewire autocontenido. Móntalo en cualquier parte de tus propios layouts en lugar de - o además de - la ruta prediseñada <code>/clearance</code>:</p><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::dashboard</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="proximos-pasos" tabindex="-1">Próximos pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos pasos&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/features/permissions.html">Permisos</a> - gestiona la lista de permisos que alimenta los recuentos del Panel de Control.</li><li><a href="/clearance-docs/es/features/roles.html">Roles</a> - gestiona los roles detrás de la estadística &quot;top 5 por número de usuarios&quot;.</li><li><a href="/clearance-docs/es/features/contextual-authorization.html">Autorización Contextual</a> - qué es una asignación de rol contextual.</li></ul>',8))])}const _=s(i,[["render",d]]);export{f as __pageData,_ as default};
